insert into public.questions (method, level, question, options, correct)
select method, level, question, options, correct
from jsonb_to_recordset($NDTA_SEED$[{"method":"MPI","level":3,"question":"When two permanent magnets are used for an MPI test you must ensure","options":["like poles contact the test surface","unlike poles contact the test surface","a gap is maintained between magnet and test piece","only wet MPI particles are used"],"correct":1},{"method":"MPI","level":3,"question":"When a specimen cannot be placed in a fixed coil on a bench unit, a flexible cable can be wound around the piece and the two ends connected to the respective poles of the bench unit.  The cable is sometimes called","options":["extension cable","wander cable","remote field cable","jumper cable"],"correct":1},{"method":"MPI","level":3,"question":"When using prods for MPI testing","options":["contact area should be as large as practicable","contact area should be as small as practicable","40 amps per cm thickness should be used","both b and c"],"correct":0},{"method":"MPI","level":3,"question":"\"Upside down\" surfaces tested using magnetic rubber techniques","options":["can not be tested","can only be tested using permanent magnets","require pressure filling a reservoir beneath the test area","\"suction cup\" contacts for prods"],"correct":2},{"method":"MPI","level":3,"question":"When performing an MPI settling test on a bath, lint or dust, and metal grindings can make up part of the settled volume.  If this occurs","options":["re-run the test after filtering out the lint and dust","include just the grinding and oxide from the total settled volume","subtract the dust and grindings volume from the total settled volume","condemn the bath and mix a new batch"],"correct":2},{"method":"MPI","level":3,"question":"The MPI technique utilizing magnetic particles in a highly viscous vehicle is termed the ________ technique.","options":["wet slurry","slow vehicle","sticky","treacle"],"correct":0},{"method":"MPI","level":3,"question":"A two phase system (usually solid and liquid) is a","options":["slurry","suspension","eutectoid","bi-tectoid"],"correct":1},{"method":"MPI","level":3,"question":"When using a calibrated ammeter to verify the MPI unit ammeter accuracy the calibrated ammeter is","options":["connected in series with the output circuit","connected in parallel with the output circuit","connected in series-parallel to the input circuit","part of a wheatsone bridge built into the MPI unit"],"correct":0},{"method":"MPI","level":3,"question":"When measuring halfwave DC with the calibrated ammeter used to verify the accuracy of the MPI units' ammeter, the current values read on the calibrated ammeter are multiplied by","options":["0.5","0.7","1","2"],"correct":3},{"method":"LPI","level":1,"question":"Contamination of dry developer powder by drops of oil or water cause","options":["segregation","small balls to form","matting on the part tested","excessive developing time"],"correct":1},{"method":"LPI","level":1,"question":"Wet developer can be agitated using a","options":["paddle","constant dipping","circulation pump","all of the above"],"correct":3},{"method":"LPI","level":1,"question":"Parts placed in a drier after wet developer is applied should be positioned so","options":["fillets and recesses drain","they do not tip during drying","the largest surface faces the fan","the smallest surface faces the fan"],"correct":0},{"method":"LPI","level":1,"question":"Inspection should occur","options":["after maximum bleed out","before maximum bleed out occurs","at various times, depending if wet or dry developer used","after development without delay"],"correct":3},{"method":"LPI","level":1,"question":"Inspection tables under the black light should be kept clean to","options":["prevent smearing of indications","prevent false indications","prevent interfering fluorescence","all of the above"],"correct":3},{"method":"LPI","level":1,"question":"Which of the following quartz tube mercury arc lamps are not recommended for LPI inspection","options":["400 watt flood","100 watt flood","100 watt spot","all of the above"],"correct":1},{"method":"LPI","level":1,"question":"If a blacklight filter is seen to be cracked, it should be replaced because","options":["unfiltered light will reduce viewing sensitivity","the filter may explode","filtered light is a safety hazard","none of the above"],"correct":2},{"method":"LPI","level":1,"question":"The difference between post-emulsified and water washable penetrants is","options":["the added step of emulsifier application","dwell time","developers used","none of the above"],"correct":0},{"method":"LPI","level":1,"question":"In the post-emulsifiable method, no emulsification time would result in","options":["extreme washability","no washability","maximum sensitivity","minimum sensitivity"],"correct":1},{"method":"LPI","level":1,"question":"In NDT, liquid penetrant testing was originally developed primarily to inspect","options":["automotive components","light alloys used in aircraft","welds","native pottery"],"correct":1},{"method":"LPI","level":1,"question":"Liquid penetrant testing detects","options":["all defects","\"piping\"","surface defects or subsurface defects with surface openings","slag"],"correct":2},{"method":"LPI","level":1,"question":"Defect detection by LPI requires","options":["that penetrant be under pressure","the defect be surface breaking","the test piece be electrically charged","a lint free environment"],"correct":1},{"method":"LPI","level":1,"question":"Liquid penetrant testing can be done on essentially","options":["all none magnetic materials","any none-radioactive solids","any material","any solid and non porous material"],"correct":3},{"method":"LPI","level":1,"question":"Which of the following steps is not common to all LPI tests","options":["emulsification time","dwell time","pre cleaning","developing time"],"correct":0},{"method":"LPI","level":1,"question":"Liquid penetrant testing has its main advantage in that it is","options":["the cheapest NDT method","essentially a simple method","the least hazardous method","used on aircraft parts"],"correct":1},{"method":"LPI","level":1,"question":"The most common foreign matter considered as a contaminant in penetrant baths is","options":["dust","chromates","water","oxygen radicals"],"correct":2},{"method":"LPI","level":1,"question":"The property which allows a penetrant to enter small openings and fine cracks is","options":["fluorescence","penetrability","solubility","emulsifiability"],"correct":1},{"method":"LPI","level":1,"question":"Water wash penetrant","options":["is not available in fluorescent form","requires only wet developer be used","has the longest bleed out time","incorporates an emulsifier"],"correct":3},{"method":"LPI","level":1,"question":"Drying time does not apply to the period of time after    the application of","options":["penetrant","wet developer","water wash","none of the above"],"correct":0},{"method":"LPI","level":1,"question":"Colour contrast dye is added to penetrants in order to    give","options":["stability to the carrier base","good visibility to flaw indications under white light","good visibility to flaw indications under black light","a compatible chemistry to the developer"],"correct":1},{"method":"LPI","level":1,"question":"The media surrounding an indication enabling an indication to be viewed is","options":["background","contrast","base","carrier"],"correct":0},{"method":"LPI","level":1,"question":"Bleed out of penetrants from a defect to be exposed by  the absorbing developer is called","options":["messy","an observation","an indication","a crack"],"correct":2},{"method":"LPI","level":1,"question":"A good penetrant must have","options":["high flash point","low cost","high stability","all of the above"],"correct":3},{"method":"LPI","level":1,"question":"The single most important property that a penetrant must have is","options":["density","viscosity","wetting ability","no single property is more important than any other"],"correct":3},{"method":"LPI","level":1,"question":"Most penetrants have a specific gravity of less than","options":["2","1.5","1","0.8"],"correct":2},{"method":"LPI","level":1,"question":"The volatility of a penetrant material","options":["should be relatively high","should be relatively low","is not a factor in material selection for penetrants","is a function of density"],"correct":1},{"method":"LPI","level":1,"question":"The temperature at which sufficient combustible vapour, under standard conditions, is given off to form an explosive mixture with the air over the liquid is called","options":["dew point","fire point","flash point","explosion point"],"correct":2},{"method":"LPI","level":1,"question":"Storing penetrants at too low a temperature can result in","options":["separation of dye from other components","increasing the flash point","explosion","decreased penetrability"],"correct":0},{"method":"LPI","level":1,"question":"Movement of penetrant into small openings is accomplished by","options":["suction","gravity","capillary action","none of the above"],"correct":2},{"method":"LPI","level":1,"question":"The single most important factor contributing to the sensitivity of a penetrant to fine cracks is","options":["handling technique","type of developer","type of penetrant","seeability"],"correct":3},{"method":"LPI","level":1,"question":"Colour perception occurs in","options":["scotopic vision","photopic vision","polyoptic vision","myopic vision"],"correct":1},{"method":"LPI","level":1,"question":"Night vision or dark adapted vision is also called","options":["photopic vision","myopic vision","scotopic vision","polyoptic vision"],"correct":2},{"method":"LPI","level":1,"question":"Highest colour contrast is provided by","options":["red dye","yellow dye","black dye","fluorescent dye"],"correct":0},{"method":"LPI","level":1,"question":"The main reason for choosing the colour red for colour contrast is","options":["its high degree of colour contrast","its high degree of solubility in most penetrant liquids","both a and b","none of the above"],"correct":2},{"method":"LPI","level":1,"question":"Water-wash fluorescent penetrants","options":["incorporate an emulsifier with the penetrant","require no black light","are the least expensive penetrants","can be used only with wet developer"],"correct":0},{"method":"LPI","level":1,"question":"Specialty penetrants, such as; leak penetrant, lox penetrant, yellow fluorescent oil free penetrant, etc., are used","options":["when money is no object","for health considerations of the operator","to meet unique test conditions","only on large rocket components"],"correct":2},{"method":"LPI","level":1,"question":"The penetrant technique employing a solvent suspension developer with a low intensity fluoragent is called","options":["the leaker technique","reversed fluorescence","oil and whiting","normal wet development"],"correct":1},{"method":"LPI","level":1,"question":"Compared to fluorescent penetrants, the amount of dye content in colour-contrast penetrants is","options":["much higher","less","about the same","varies depending on application"],"correct":0},{"method":"LPI","level":1,"question":"A safety advantage of most dyes is that they have","options":["low toxicity","low flash point","chemical inertness","low volatility"],"correct":0},{"method":"LPI","level":1,"question":"The function of developer is to","options":["soak up excess penetrant","absorb black light","make penetrant visible at defects","none of the above"],"correct":2},{"method":"LPI","level":1,"question":"A property a penetrant need not have is","options":["fine grained particle structure","easy and even applicability","high solubility in water","easy removal"],"correct":2},{"method":"LPI","level":1,"question":"Which of the following is not a normally recognized developer type","options":["dry powder developer","fluorescent developer","water suspension developer","solvent suspension developer"],"correct":1},{"method":"LPI","level":1,"question":"Which of the following is not an application method for dry developer","options":["electro static fields","magnetic fields","dipping","air assist spraying"],"correct":1},{"method":"LPI","level":1,"question":"Removal of developer powder is","options":["essential in all situations","never required","a health consideration","none of the above"],"correct":3},{"method":"LPI","level":1,"question":"Water suspendible developers have the advantage of","options":["speeding up application of developer","application to many small parts at one time","quick thorough coverage over all surfaces","all of the above"],"correct":3},{"method":"LPI","level":1,"question":"Which of the following is not a method of application of wet developer","options":["dipping","electrostatic","flow-on","spray-on"],"correct":1},{"method":"LPI","level":1,"question":"In automatic units, uniform density of water suspension developer is maintained by","options":["shaking","stir sticks","pump agitators","none of the above, agitation is not needed in automatic units"],"correct":2},{"method":"LPI","level":1,"question":"Water suspendible developer, if required to be removed, is best removed by","options":["sand blasting","warm water and detergent","tri-chlorethanal","steam cleaning"],"correct":1},{"method":"LPI","level":1,"question":"In addition to providing quick drying developer, solvents in solvent suspendible developers","options":["aid in post cleaning","eliminate the need for emulsifiers","dissolve penetrant and give it a greater mobility","none of the above"],"correct":2},{"method":"LPI","level":1,"question":"Solvent developer is applied by","options":["air pressure spray guns","paint brush","aerosol spray can","all of the above"],"correct":3},{"method":"LPI","level":1,"question":"On smooth surfaces the best developer to use with fluorescent penetrants is","options":["solvent suspendible","water suspendible","dry-regular","dry-fluffy"],"correct":1},{"method":"LPI","level":1,"question":"In addition to being free from dirt, rust and scale, to LPI, a part must also be","options":["smooth","cool","dry","none of the above is necessary"],"correct":2},{"method":"LPI","level":1,"question":"When practical, the easiest way to apply penetrants is","options":["dipping","flowing","electrostatics","aerosol spray"],"correct":0},{"method":"LPI","level":1,"question":"Penetration time to detect porosity as compared to fatigue cracks is generally","options":["longer","shorter","about the same","two and a half times shorter"],"correct":0},{"method":"LPI","level":1,"question":"Depending on the penetrant used, removal of excess is accomplished by","options":["water wash","solvent cleaning","dry wiping","all of the above"],"correct":3},{"method":"LPI","level":1,"question":"Dry cloth wiping to remove penetrants has the advantage that","options":["it is the fastest method","it removes no penetrant from defects","it is the cleanest method","all of the above"],"correct":1},{"method":"LPI","level":1,"question":"In order to be water-washable, penetrants must contain","options":["dye","solvents","emulsifier","all of the above"],"correct":2},{"method":"LPI","level":1,"question":"The removal of excess penetrant by rag wipe is most effective on","options":["welds","cast aluminium","glass","cast steel"],"correct":2},{"method":"LPI","level":1,"question":"Maximum wash temperature for removal of post-emulsified penetrant is","options":["room temperature","40 degrees F.","110 degrees F.","100 degrees C."],"correct":2},{"method":"LPI","level":1,"question":"When using fluorescent penetrants, a black light is often placed at the","options":["penetrant station","developer station","removal or wash station","none of the above"],"correct":2},{"method":"LPI","level":1,"question":"Ambient air drying","options":["is slow","results in uneven drying","blurs indication formation","all of the above"],"correct":3},{"method":"LPI","level":1,"question":"The most effective means of drying a part is","options":["cloth wipe","hot air","use of volatile solvents","compressed air blasts"],"correct":1},{"method":"LPI","level":1,"question":"Penetrant tends to come out of surface openings more rapidly when","options":["the part is vibrated","the part is heated","the penetrant if fluorescent","developer is wet"],"correct":1},{"method":"LPI","level":1,"question":"Air temperature in a recirculating air dryer is generally recommended to be","options":["Just over the boiling point of water","40 degrees C.","100 degrees F.","400 degrees F."],"correct":0},{"method":"LPI","level":1,"question":"Drying after application of wet developer is best achieved by","options":["wiping","air blast","slow drying at room temperature","hot air drying"],"correct":3},{"method":"LPI","level":1,"question":"Where parts are few or large the preferred developer is","options":["water soluble","water suspendible","solvent","dry powder"],"correct":3},{"method":"LPI","level":1,"question":"Which is not an advantage of wet developer?","options":["easy to apply to large numbers of small parts","completeness of coverage","sharper definition","easy to apply to very large parts"],"correct":3},{"method":"LPI","level":1,"question":"Inspection of a part without sufficient development time can result in","options":["false indications","irrelevant indications","missed indications","none of the above"],"correct":2},{"method":"LPI","level":1,"question":"A group of compatible penetrants, cleaners and developers is called a","options":["group","sub-unit","factor","family"],"correct":3},{"method":"LPI","level":1,"question":"Occasional exposure of skin to penetrants will usually result in","options":["cancer","irritation","no noticeable effect","caustic burns"],"correct":2},{"method":"LPI","level":1,"question":"Which is not a contaminant of penetrants used in dip tanks","options":["solvents","dirt","water","evaporation"],"correct":3},{"method":"LPI","level":1,"question":"The most common and critical contaminant of water washable penetrants is","options":["water","dirt","chromates","solvents"],"correct":0},{"method":"LPI","level":1,"question":"Because of emulsifiers in water-washable penetrants they have been used to wash greasy hands","options":["this deteriorates the penetrant","the operator may get cancer","the operator may get sore hands","subsequent tests are less sensitive"],"correct":2},{"method":"LPI","level":1,"question":"In leak detection using liquid penetrants the best penetrating ability is had using","options":["water washable colour contrast penetrant","water washable fluorescent penetrant","post emulsifiable penetrant","all penetrants are about the same"],"correct":2},{"method":"LPI","level":1,"question":"To verify a leak location when performing penetrant leak detection","options":["the operator waits for a drip to form","developer is added and the pattern observed","the test is re-run with a different colour dye","the wet spot is wiped off and watched for re-appearance"],"correct":3},{"method":"LPI","level":1,"question":"Recommended inspection temperature for \"the penetrant bath\" is","options":["70 degrees F.","70 degrees C.","110 degrees F.","40 degrees F."],"correct":0},{"method":"LPI","level":1,"question":"Failure to remove all dirt, rust and scale can result in","options":["missed defects","excessive background","both a and b","none of the above"],"correct":2},{"method":"LPI","level":1,"question":"For manual inspection of many small parts, the preferred penetrant application method is","options":["aerosol spray","hose and nozzle","basket dipping","electrostatics"],"correct":2},{"method":"LPI","level":1,"question":"The expendable penetrant technique is used on","options":["small parts","government jobs","aircraft","local areas of large parts"],"correct":3},{"method":"LPI","level":1,"question":"Drain time for small parts of the same material and when looking for the same defect type as on large parts is","options":["much shorter","half the time","proportional to the size","the same time"],"correct":3},{"method":"LPI","level":1,"question":"Water used to remove water washable penetrants in large volume facilities is","options":["easily disposed of down any drain","to be collected and oils separated","reusable","a problem for Greenpeace"],"correct":1},{"method":"LPI","level":1,"question":"Open shallow defects are more detectable using the post-emulsifiable method because","options":["P.E. penetrant is sticky","penetrability is controlled","dwell time is much greater","washability is controlled"],"correct":3},{"method":"LPI","level":1,"question":"Post emulsifiable penetrants can be made with","options":["high tolerance to water","very high brilliance dyes","anthrax","none of the above"],"correct":1},{"method":"LPI","level":1,"question":"Because post emulsifiable penetrant has a low water tolerance","options":["penetrant can be added to water-wet parts","penetrant tanks are not contaminated by water","they are best applied by spray can","none of the above"],"correct":1},{"method":"LPI","level":1,"question":"The main disadvantage of the post emulsifiable method is","options":["its inability to detect fine cracks","its poor re-run performance","the fact it is a time consuming method","the P.E. method had no disadvantages"],"correct":2},{"method":"LPI","level":1,"question":"Water contamination in post emulsifiable penetrants is","options":["measured as a percent to total volume","reduced in the fluorescent variety","not a serious consideration","what turns the penetrant milky"],"correct":2},{"method":"LPI","level":1,"question":"In order that an emulsifier be useful in open dip tanks it should have","options":["low flash point","low evaporation rate","both a and b","none of the above"],"correct":1},{"method":"LPI","level":1,"question":"Which is not a desirable quality of an emulsifier?","options":["high volatility","high tolerance to contaminating water","high tolerance to contaminating penetrant","non-toxic"],"correct":0},{"method":"LPI","level":1,"question":"Solvents in the make-up of some post emulsifiable penetrants may attack","options":["chrome","titanium","brass","plastic"],"correct":3},{"method":"LPI","level":1,"question":"Which is not a recommended method to apply emulsifier?","options":["dipping","paint brush","spray nozzles","flow on"],"correct":1},{"method":"LPI","level":1,"question":"Tolerance of water washable penetrants and emulsifiers to water is calculated by","options":["qualitative measures","the amount of water added to the sample","volume water divided by total volume all times 100","none of the above"],"correct":2},{"method":"LPI","level":1,"question":"If a penetrant was stable under elevated temperatures, it would show ___________________ upon heating to 130 degrees F.","options":["slight change of colour","signs of insolubles precipitating","small flakes float to the surface","none of the above"],"correct":3},{"method":"LPI","level":1,"question":"A penetrant stored in a cool place (-20 degrees C) is then to be used at room temperature but is noticed to have separated.  It is considered","options":["toxic","inverted","unstable","chilled"],"correct":2},{"method":"LPI","level":1,"question":"Density of penetrant materials can be measured in","options":["grams per cubic centimetre","specific gravity","pounds per gallon","all of the above"],"correct":3},{"method":"LPI","level":1,"question":"Measurement of flashpoint is important","options":["to determine surface tension","as a safety standard","to ensure no toxicity","for post-emulsifiable penetrants only"],"correct":1},{"method":"LPI","level":1,"question":"The process of examining materials for possible defects or deviation from standards is called","options":["production control","configuration management","non destructive testing","inspection"],"correct":3},{"method":"LPI","level":1,"question":"The process of inspecting a part for surface or sub-surface defects without altering or damaging the part is called","options":["quality control","non destructive testing","statistical analysis","eddy current testing"],"correct":1},{"method":"LPI","level":1,"question":"A discontinuity which is not open to the surface of a test part is called","options":["a subsurface discontinuity","nonrelevant","a non LPI defect","insignificant"],"correct":0},{"method":"LPI","level":1,"question":"The extent and brightness of a penetrant indication depends on the discontinuity","options":["length","width","depth","volume"],"correct":3},{"method":"LPI","level":1,"question":"Other aspects being equal, the time for an indication to develop is","options":["5 minutes","proportional to the volume of the defect","inversely proportional to the volume of the defect","none of the above"],"correct":2},{"method":"LPI","level":1,"question":"The biggest problem with doing penetrant testing on rough surfaces is","options":["low penetrability of the rough surface","limited application methods available","the inability to use plastic developers","difficulty in removing excess penetrant"],"correct":3},{"method":"LPI","level":1,"question":"If a part (or penetrant) is too cold, the result may be","options":["penetrant not entering fine defects","difficult removal of excess penetrant","excessive bleed out","none of the above"],"correct":0},{"method":"LPI","level":1,"question":"When penetrant testing is used for leak detection and a glass tank found to be leaking it is important to establish if the leak source is from","options":["porosity","a crack","now fusion","the source is not important if leaking"],"correct":3},{"method":"LPI","level":1,"question":"The most objectionable defect located by LPI is usually","options":["cracking","non-fusion","porosity","corrosion"],"correct":0},{"method":"LPI","level":2,"question":"Which is not a developer used in liquid penetrant testing?","options":["solvent developer","wet developer","Farmer's solution","dry developer"],"correct":2},{"method":"LPI","level":2,"question":"Which of the following is not a good quality for penetrants","options":["easily penetrate fine openings","high volatility","easily wipe off the applied surface","able to remain in coarse openings"],"correct":1},{"method":"LPI","level":2,"question":"A good penetrant should","options":["be inert with respect to the test material","have very low viscosity","have a low flash point","be insoluble"],"correct":0},{"method":"LPI","level":2,"question":"A problem with using a liquid with a low viscosity for a  penetrant is","options":["dwell time is too long","thinner liquids are more likely to be removed by cleaning","it cannot be emulsified","there is no problem"],"correct":1},{"method":"LPI","level":1,"question":"Which is not a recommended method of washing penetrant/emulsifier off when using the post emulsifiable method?","options":["wet rag wipe","solvent spray","dip washing","all of the above"],"correct":3},{"method":"LPI","level":1,"question":"The best method for drying when using the postemulsifiable method is","options":["infra-red lamps","re-circulating warm air dryers","high velocity warm air blowers","wiping with a dry cloth"],"correct":1},{"method":"LPI","level":1,"question":"If dry developer is contaminated by fluorescent penetrant the result is","options":["unnecessary rejection of parts","irrelevant spots of fluorescence on test parts","dark spots on a white background","deterioration of developer"],"correct":1},{"method":"LPI","level":1,"question":"Black light refers to","options":["infra red radiation","far ultraviolet radiation","near ultraviolet radiation","soft gamma radiation"],"correct":2},{"method":"LPI","level":1,"question":"Black light is so called because","options":["it is seen only in darkened areas","it is a by-product of white radiation","it cannot be seen with the human eye","none of the above"],"correct":2},{"method":"LPI","level":1,"question":"Short wavelength UV light (less than 3000 angstroms) must be filtered out","options":["because it is hazardous","to be useful as blacklight","to reduce deterioration of dyes","none of the above"],"correct":0},{"method":"LPI","level":1,"question":"Blacklight is produced by","options":["welding","the sun","mercury vapour arc","all of the above"],"correct":3},{"method":"LPI","level":1,"question":"The best source of useful blacklight for fluorescent penetrant testing is","options":["sunlight","tungsten inert gas","mercury-vapour arc","incandescent tungsten"],"correct":2},{"method":"LPI","level":1,"question":"Harmful UV and annoying white light are eliminated from the mercury vapour arc by","options":["signal averaging","convolution","deconvolution","filtering"],"correct":3},{"method":"LPI","level":1,"question":"Tubular black lights are not recommended for fluorescent LPI because","options":["they cannot be properly filtered","they cause \"eye-ball fluorescence\"","insufficient viewing intensity is achieved on the inspection surface","output is not peaked at 365 nm"],"correct":2},{"method":"LPI","level":1,"question":"Mercury vapour lamps contain a small quartz tube which houses","options":["electrodes","heater element","mercury","all of the above"],"correct":3},{"method":"LPI","level":1,"question":"In the high pressure mercury vapour  lamps, the mercury is housed in","options":["the thermostat","a quartz tube","a ballast","the electrodes"],"correct":1},{"method":"LPI","level":1,"question":"When measuring blacklight intensity with an appropriate light meter you should use","options":["a filter that passes UV light only","a filter that passes white light","a filter that blocks infra-red","no filter"],"correct":0},{"method":"LPI","level":1,"question":"Black light intensity from a standard mercury vapour lamp may vary due to","options":["the isotope of mercury used","line voltage supplied by utilities","both a and b","none of the above"],"correct":1},{"method":"LPI","level":1,"question":"Black light intensity from a standard mercury vapour lamp may vary due to","options":["aging","dirt on the filter","both a and b","none of the above"],"correct":2},{"method":"LPI","level":1,"question":"In order for the starter electrode to warm up the mercury vapour, a warm up time for the blacklight of ____ minutes is required.","options":["2","5","10","15"],"correct":1},{"method":"LPI","level":1,"question":"Eyeball fluorescence results from direct or reflected blacklight to the eye.  The result is","options":["annoying but harmless","interference with vision during inspection","both a and b","none of the above"],"correct":2},{"method":"LPI","level":1,"question":"Optimum placement distance for inspection with a 100 watt portable spot blacklight is","options":["200 cm","350 cm","500 cm","750 cm"],"correct":1},{"method":"LPI","level":1,"question":"The recording of liquid penetrant indications can be accomplished by","options":["photography","hand sketches","written description","all of the above"],"correct":3},{"method":"LPI","level":1,"question":"Colour contrast penetrants are available in","options":["water washable type","solvent washable type","post emulsifiable type","all of the above"],"correct":3},{"method":"LPI","level":1,"question":"Which is not an advantage of the colour contrast method over the fluorescent method?","options":["no black light needed","portable and simple to use","low cost","highest sensitivity to fine cracks"],"correct":3},{"method":"LPI","level":1,"question":"The best way to compare the seeability of LPI systems is","options":["light meters","aluminium test blocks","the Rockwell test","none of the above"],"correct":1},{"method":"LPI","level":1,"question":"The developer carrier liquid","options":["is always alcohol","must be of low density","must have medium  viscosity","provides the vehicle to distribute developer evenly and at the proper thickness"],"correct":3},{"method":"LPI","level":1,"question":"When wet developer is applied to several surfaces on the same part","options":["drying is always a problem","small surfaces are done first","large surfaces are done first","care must be taken that no suspect areas are touched"],"correct":3},{"method":"LPI","level":1,"question":"Generally indications from large defects","options":["appear first","are sharper than from small defects","require more developer","are always visible without penetrant testing"],"correct":0},{"method":"LPI","level":1,"question":"Lighting for colour-contrast inspection should be","options":["high intensity spot lights","bright white light","equal amounts of UV and white light","all of the above are alright"],"correct":1},{"method":"LPI","level":1,"question":"For viewing of colour-contrast indications, adequate light is had from _________ watt bulbs in a hand held shielded fixture","options":["25","60","100","400"],"correct":2},{"method":"LPI","level":1,"question":"Hand application of penetrant inspections can be performed","options":["if only a few parts are to be inspected","if sensitivity is not critical","as a last resort on large pieces when no equipment is available","all of the above"],"correct":3},{"method":"LPI","level":1,"question":"When using water-wash systems, even in small volume shops, the single most important piece of equipment is the","options":["penetrant dip tank","developer dip tank","aluminum test block","recirculating hot air drier"],"correct":3},{"method":"LPI","level":1,"question":"Fluorescent penetrant dip tanks should be equipped with a cover","options":["to avoid splashing","because white light breaks down the dyes","to minimize evaporation losses","to avoid chances of dipping emulsified parts back into the penetrant"],"correct":2},{"method":"LPI","level":1,"question":"To inspect large parts, penetrant dip tanks can be equipped with","options":["re-enforced steel legs","expandable walls","hose, nozzle and pump","hydraulically lifted drain racks"],"correct":2},{"method":"LPI","level":1,"question":"Developer on a test piece is","options":["re-usable","re-usable only if the part has no defects","reusable only if dry powder is used","not reusable"],"correct":3},{"method":"LPI","level":1,"question":"The wash station should be equipped with________ when inspecting small parts with fluorescent penetrant","options":["black lights","hose and nozzle","splash shields","all of the above"],"correct":3},{"method":"LPI","level":1,"question":"If wet developer is used the drying station is located","options":["before the emulsifier station","before the developer station","after the developer station","after the inspection station"],"correct":2},{"method":"LPI","level":1,"question":"If dry developer is used, the drying station is located","options":["before the emulsifier station","before the developer station","after the developer station","after the inspection station"],"correct":1},{"method":"LPI","level":1,"question":"Wet developer stations are often equipped with","options":["pumps or paddle for agitation","drain racks","both a and b","none of the above"],"correct":2},{"method":"LPI","level":1,"question":"If you use \"paint spray\" type pressurized containers it is possible to apply _______ using the expendible technique.","options":["penetrant","water suspendable wet developer","solvent suspendable wet developer","all of the above"],"correct":3},{"method":"LPI","level":1,"question":"A minimum kit for colour contrast penetrant inspection would include","options":["pre-cleaner, penetrant, emulsifier, developer","penetrant, developer, solvent remover","pre cleaner, developer, penetrant, solvent remover","none of the above"],"correct":1},{"method":"LPI","level":1,"question":"A minimum kit for fluorescent penetrant inspection would include","options":["pre-cleaner, daylight penetrant, developer","pre-cleaner, daylight penetrant, emulsifier, developer","penetrant, developer, remover and black light","penetrant, precleaner, remover, developer, blacklights"],"correct":2},{"method":"LPI","level":1,"question":"Penetrant inspection will find most defects which","options":["have a depth equal to or greater than width","are found in non-ferrous materials","break the surface of non porous solids","cannot be found by eddy current"],"correct":2},{"method":"LPI","level":1,"question":"Which of the following would be the most detrimental type of defect, assuming size was about the same in all cases?","options":["v-shaped","rounded u-shaped","spherical shaped","all would be about the same critically"],"correct":0},{"method":"LPI","level":1,"question":"Detectability of defects is primarily a function of","options":["processes through which the part has undergone","the form of the material tested","defect characteristics","work history of the part"],"correct":2},{"method":"LPI","level":1,"question":"Which is not a consideration when choosing the LPI method, material and technique to be used","options":["number of defects to be found","number of parts to be tested","inspection rate","cost"],"correct":0},{"method":"LPI","level":1,"question":"Basically there are only __________ types of penetrants.","options":["2","3","4","5"],"correct":0},{"method":"LPI","level":1,"question":"An environmental limitation of the LPI method could be","options":["chemical reaction with the test piece","risk by inflammable penetrant","areas where liquid oxygen will be used","all of the above"],"correct":3},{"method":"LPI","level":1,"question":"For locating very tight surface cracks the penetrant should be","options":["of high penetrating ability","used with wet developer","colour contrast solvent removable","none of the above"],"correct":0},{"method":"LPI","level":1,"question":"Porosity is a commonly found defect in","options":["alumimum castings","magnesium castings","steel castings","all of the above"],"correct":3},{"method":"LPI","level":1,"question":"Good penetrating ability in a penetrant used for detecting porosity","options":["must be determined with side drilled holes","is evaluated on a ketose ring","is essential for piping porosity","is not required"],"correct":3},{"method":"LPI","level":1,"question":"An indication resulting form poor washing of a rough surface results in","options":["porosity","rejections","non-relevant indications","false indications"],"correct":3},{"method":"LPI","level":1,"question":"False indications or noise from excess background penetrant should be noticed","options":["at the time of inspection","by the level I operator","at the wash station","only in fluorescent inspections"],"correct":2},{"method":"LPI","level":1,"question":"Which is not a casting defect?","options":["blow holes","age cracking","laps","cold shut"],"correct":2},{"method":"LPI","level":1,"question":"The main defects found in die castings are","options":["slag and porosity","porosity and shrinkage","shrinkage and sand inclusions","cold shuts and cold shots"],"correct":1},{"method":"LPI","level":1,"question":"A burst is a ________ defect.","options":["casting","process","weld","forging"],"correct":3},{"method":"LPI","level":1,"question":"Flakes, seams and piping are________ defects.","options":["Forging","casting","process","weld"],"correct":0},{"method":"LPI","level":1,"question":"Liquid penetrant testing of billets","options":["can detect lack of fusion","prevents oxide build up","is used to eliminate defects which may result after rolling","is not recommended"],"correct":2},{"method":"LPI","level":1,"question":"LPI cannot be used as a preventative maintenance for","options":["fatigue cracks","stress corrosion cracking","over loading","aging cracks"],"correct":2},{"method":"LPI","level":1,"question":"Penetrants used in the food industry are","options":["odourless","non-toxic","colour contrast only","all of the above"],"correct":3},{"method":"LPI","level":1,"question":"In which of the following could even a small leak render the component useless?","options":["a vacuum housed semiconductor","a natural gas pipeline","a crude oil tank","a steam generator boiler"],"correct":0},{"method":"LPI","level":1,"question":"Leak testing using hydraulic fluids under pressure can require the operator look for a drop in","options":["density","pressure","specific gravity","fluorescence"],"correct":1},{"method":"LPI","level":1,"question":"When testing a vessel for leaks when the vessel cannot be sealed, penetrant is","options":["applied in a vacuum chamber","applied in a larger pressure vessel","used to fill the vessel","mixed with a sealant"],"correct":2},{"method":"LPI","level":1,"question":"The best time to examine a tank for leaks using liquid penetrant is","options":["at the time of fabrication","during installation","during operation","anytime is as good as any other"],"correct":0},{"method":"LPI","level":1,"question":"Leak detection techniques using liquid penetrant are used to test","options":["washing machine tubs","dual pane glass windows","electronic capacitors","all of the above"],"correct":3},{"method":"LPI","level":1,"question":"Leak detection using liquid penetrant techniques gives best results on","options":["thick materials","thin materials","plastic materials","ceramics"],"correct":1},{"method":"LPI","level":1,"question":"Liquid penetrant indications give","options":["exact dimensions of defects","indirect information about defects located","bleed out dimensions proportional to defect length","indications about twice the depth dimension"],"correct":1},{"method":"LPI","level":1,"question":"Ascertaining the acceptability of a defect indication is called","options":["interpretation","evaluation","rejection criteria","viewing"],"correct":1},{"method":"LPI","level":1,"question":"Determining the cause or nature of a liquid penetrant indication is","options":["interpretation","evaluation","established by codes","difficult"],"correct":0},{"method":"LPI","level":1,"question":"Non-relevant indications are the result of","options":["handling","poor washing","assembly or geometry","contamination of developer with penetrant"],"correct":2},{"method":"LPI","level":1,"question":"Certification of personnel is","options":["regulated by a central government agency","the responsibility of the testing company","given only after examination","different in different countries"],"correct":3},{"method":"LPI","level":1,"question":"Which is not a physical property for which liquid penetrant might be tested?","options":["penetrability","flash point","viscosity","density"],"correct":0},{"method":"LPI","level":1,"question":"Suitability of a particular penetrant for a specific application would not be determined by","options":["sensitivity test","fluorescent brightness comparison test","flash point test","developer wetting ability"],"correct":2},{"method":"LPI","level":1,"question":"Aluminum test blocks are used for","options":["measurement of penetrant corrosiveness","establishing quantitative values of fluorescence","comparison studies of penetrant materials","age of emulsifier"],"correct":2},{"method":"LPI","level":1,"question":"A disadvantage of using the cracked aluminum test block is","options":["only one method of test can be compared","only 3 or 4 tests can be run on a block","they are difficult to prepare","defect depths vary"],"correct":1},{"method":"LPI","level":1,"question":"On the aluminum test block a 1/16\" X 1/16\" groove is cut on","options":["one side","two sides","one side and in two directions","two sides at right angles to each other"],"correct":1},{"method":"LPI","level":1,"question":"When using the aluminum test block for comparisons, the test family is applied to","options":["one half of one face of the block","both halves of one face of the block","one half of both faces of the block","both halves of both faces of the block"],"correct":0},{"method":"LPI","level":1,"question":"The reference standard family of penetrant materials is applied to the _________ on the aluminum test block.","options":["adjacent half of the test family","opposite face","test family","none of the above"],"correct":0},{"method":"LPI","level":1,"question":"The best means of verifying a test systems' sensitivity is","options":["the manufacturer's guarantee","the Charpy test","comparative tests on the aluminum test block","by means of a photometer"],"correct":2},{"method":"LPI","level":1,"question":"If a penetrant has a water tolerance of 20%, it would be permissible to use it until the water content reached","options":["2%","18%","20%","22%"],"correct":1},{"method":"LPI","level":1,"question":"The biggest source of contaminants in emulsifiers is","options":["penetrant","water","developer","lint"],"correct":0},{"method":"LPI","level":1,"question":"If the concentration of water suspendable wet developer is found to be above recommended levels","options":["it is discarded","more water is added","more developer is added","the mixture is heated to 80 degrees C."],"correct":1},{"method":"LPI","level":1,"question":"Developer fluorescence resulting from contamination by penetrant is tested for by","options":["oil and whiting","black light","photofluorimeters","galvanometers"],"correct":1},{"method":"LPI","level":1,"question":"Which is not a reason for using liquid penetrant as the test method","options":["electricity is not available","the test material is non-magnetic","the test piece has large changes in section","large numbers of pieces are to be tested"],"correct":3},{"method":"LPI","level":1,"question":"Operator eye fatigue in blacklight viewing can result from","options":["clothing dyes fluorescing","damaged filters","extraneous outside light sources","all of the above"],"correct":3},{"method":"LPI","level":1,"question":"It is customary for LPI inspectors to have eye examinations to test for","options":["visual acuity","colour vision","distance perception","all of the above"],"correct":3},{"method":"LPI","level":1,"question":"There are _________ basic steps in liquid penetrant testing.","options":["3","5","6","4 or 5"],"correct":2},{"method":"LPI","level":1,"question":"Detectability of LPI indications can be improved by","options":["neutron bombardment","magnifying glasses","white light filters","none of the above"],"correct":1},{"method":"LPI","level":1,"question":"Hydrophilic emulsifiers are preferred over lipophilic emulsifiers because","options":["they are cheaper","they allow better control of removal","drying time is reduced","bleedout time is reduced"],"correct":1},{"method":"LPI","level":1,"question":"For hand wipe penetrant removal solvents can be used for penetrant removal","options":["if applied to the part as a fine mist","by flow on if the part is rough","if applied by a lightly moistened cloth","under no circumstance"],"correct":2},{"method":"LPI","level":1,"question":"The advantage of colour contrast penetrant is","options":["the repair welder can see where the weld defect is to be repaired","emulsifier is never required","subdued lighting is adequate","it is more sensitive than fluorescent penetrant"],"correct":0},{"method":"LPI","level":1,"question":"The purpose of the liquid carrier in penetrants is to","options":["hold the dye in solution or suspension","distribute the inspection penetrant evenly over the test piece","carry the inspection penetrant into discontinuities","all of the above"],"correct":3},{"method":"LPI","level":1,"question":"The temperature at which the vapour-air mixture first ignites is called","options":["dew point","ignition temperature","flash point","vapour point"],"correct":2},{"method":"LPI","level":1,"question":"Highly water soluble water-washable penetrants","options":["are hardest to remove","are susceptible to overwashing","have low flash points","are the most sensitive"],"correct":1},{"method":"LPI","level":1,"question":"When washing off excess fluorescent water washable penetrant, washing is completed","options":["in 2 minutes","when background fluorescence is gone","without a black light","prior to application of emulsifier"],"correct":1},{"method":"LPI","level":1,"question":"Excessive emulsification time will result in","options":["over development","under development","failure to produce flaw indications","excessive background"],"correct":2},{"method":"LPI","level":1,"question":"If a part that has been tested with a post emulsifiable penetrant does not rinse clean it should be","options":["put back into the emulsifier bath","rinsed again with hot water","rinsed again using higher water pressure","reprocess the part starting with precleaning"],"correct":3},{"method":"LPI","level":1,"question":"Excessive contamination of emulsifier in tanks by penetrant will result in","options":["reduced emulsifier activity","longer emulsification dwell times","difficulty rinsing emulsified penetrant off","all of the above"],"correct":3},{"method":"LPI","level":1,"question":"The reason fluorescent dyes are usually yellow or yellow green is because","options":["the human eye has maximum sensitivity in this range","it is the only colour available for penetrants","these dyes are least likely to deteriorate","these dyes flash to make them more visible"],"correct":0},{"method":"LPI","level":1,"question":"All liquid penetrant indications are","options":["relevant","rejectable","non-relevant","to be interpreted"],"correct":3},{"method":"LPI","level":1,"question":"In the LPI context, the term \"bath\" refers to","options":["penetrants only","water rinse","all penetrant materials in immersion tanks intended for reuse","emulsifiers and penetrants"],"correct":2},{"method":"LPI","level":1,"question":"High temperature penetrants","options":["have very high flash points","are designed for use on high temperature surfaces","are only available in fluorescent type","have a high curie point"],"correct":1},{"method":"LPI","level":1,"question":"The advantage of penetrants used from aerosol cans is","options":["no contaminants","consistent performance","relative cleanliness and portability","all of the above"],"correct":3},{"method":"LPI","level":1,"question":"Most comparison tests of penetrant materials are done","options":["with a black light","with aluminum test blocks","against a reference standard","at the start of each shift"],"correct":2},{"method":"LPI","level":1,"question":"A sudden change in penetrant materials' performance can result from","options":["an increase in wash-water temperature","a sudden increase in heater temperature","solvent contamination of emulsifier","all of the above"],"correct":3},{"method":"LPI","level":1,"question":"Standard crack test samples eventually become unusable because","options":["the cracks become too large to be reliable","residues build up an prevent penetrant entering cracks","of too many finger prints","emulsifier etches the crack edges"],"correct":1},{"method":"LPI","level":1,"question":"Hydrophilic and lipophilic are used to describe","options":["penetrants","emulsifiers","developers","Australian surfers"],"correct":1},{"method":"LPI","level":1,"question":"Penetrants that include an emulsifier as part of their make-up are called","options":["water-washable","colour contrast","fluorescent","hydrophilic"],"correct":0},{"method":"LPI","level":1,"question":"Emulsification time is determined by","options":["the manufacturer of the emulsifier","specified code","experiment by the operator","all of the above"],"correct":2},{"method":"LPI","level":1,"question":"Hydrophilic emulsifiers are applied by","options":["immersion","dip","spray","all of the above"],"correct":3},{"method":"LPI","level":1,"question":"A desirable physical property for a developer to have is","options":["high capillary efficiency","high solubility","high absorption coefficient for white and black light","low thermal expansion"],"correct":0},{"method":"LPI","level":1,"question":"The method used to apply developer is determined by","options":["type of developer used","size of test piece","facilities available","all of the above"],"correct":3},{"method":"LPI","level":1,"question":"Non-aqueous solvent suspendible developers have the advantage that","options":["they are the fastest to apply","no drier is needed after application","they are the cheapest developer","all of the above"],"correct":1},{"method":"LPI","level":1,"question":"Thickness of developer is","options":["not critical","regulated by drying time","a determining factor in sensitivity","all of the above"],"correct":2},{"method":"LPI","level":1,"question":"Fluorescent brilliance of penetrant is usually measured as a comparative quantity.  The standard for comparison is usually","options":["obtained by special request to the manufacturer","supplied by the military","an unused sample of the penetrant in use","government certified"],"correct":2},{"method":"LPI","level":1,"question":"The two most common defect specimens used to compare LPI material or methods are","options":["vee grooves and EDM notches","chrome plated brass panels and quench cracked aluminium blocks","EDM notches and quench cracked aluminum blocks","none of the above"],"correct":1},{"method":"LPI","level":1,"question":"Where water is a possible surface contaminant, it can be removed using","options":["air drying","forced dry air","oven drying at elevated temperature","all of the above"],"correct":3},{"method":"LPI","level":1,"question":"Water soluble developers are best removed from the test piece by","options":["solvent remover","acid etch","vapour degreasing","coarse water spray"],"correct":3},{"method":"LPI","level":1,"question":"As time increases from the time of developer application, indications appear and reach optimum clarity.  Further development results in","options":["no change","increased visibility","reduced resolution and intensity","reversal"],"correct":2},{"method":"LPI","level":1,"question":"A factor which does not affect emulsification time is","options":["surface condition","type of emulsifier","type of defect sought","precleaning method used"],"correct":3},{"method":"LPI","level":1,"question":"Visible dye penetrants that get onto clothing are best removed by","options":["cold water and scrubbing","hot water and detergent","dry cleaning","acid etching"],"correct":2},{"method":"LPI","level"